/**
 * Chat WebSocket client for real-time streaming.
 * Uses native WebSocket API with HTMX-style DOM updates.
 */

(function() {
    'use strict';

    const WS_URL = `ws://${window.location.host}/ws/chat/`;
    const MESSAGES_LIST = document.getElementById('messages-list');
    const MESSAGES_CONTAINER = document.getElementById('messages-container');
    const CHAT_FORM = document.getElementById('chat-form');
    const MESSAGE_INPUT = document.getElementById('message-input');
    const SEND_BUTTON = document.getElementById('send-button');
    const CONNECTION_STATUS = document.getElementById('connection-status');
    const TYPING_TEMPLATE = document.getElementById('typing-indicator-template');

    let ws = null;
    let isStreaming = false;
    let currentAssistantMessage = null;

    /**
     * Initialize WebSocket connection.
     */
    function initWebSocket() {
        showConnectionStatus('Connecting...', 'connecting');

        try {
            ws = new WebSocket(WS_URL);

            ws.onopen = function() {
                showConnectionStatus('Connected', 'connected');
            };

            ws.onclose = function(event) {
                showConnectionStatus('Disconnected', 'disconnected');
                ws = null;
                // Auto-reconnect after delay
                if (!event.wasClean) {
                    setTimeout(initWebSocket, 3000);
                }
            };

            ws.onerror = function(error) {
                console.error('WebSocket error:', error);
                showConnectionStatus('Error', 'error');
            };

            ws.onmessage = function(event) {
                handleMessage(JSON.parse(event.data));
            };
        } catch (e) {
            console.error('Failed to create WebSocket:', e);
            showConnectionStatus('Failed to connect', 'error');
        }
    }

    /**
     * Handle incoming WebSocket messages.
     */
    function handleMessage(data) {
        switch (data.type) {
            case 'received':
                // Server acknowledged the message
                showTypingIndicator();
                break;

            case 'token':
                // Stream token from model
                appendToken(data.content);
                break;

            case 'complete':
                // Response complete
                hideTypingIndicator();
                isStreaming = false;
                currentAssistantMessage = null;
                enableInput();
                break;

            case 'error':
                // Error from server
                hideTypingIndicator();
                showError(data.error);
                isStreaming = false;
                currentAssistantMessage = null;
                enableInput();
                break;
        }

        scrollToBottom();
    }

    /**
     * Append a token to the current assistant message.
     */
    function appendToken(token) {
        if (!currentAssistantMessage) {
            hideTypingIndicator();
            currentAssistantMessage = createMessageElement('assistant', '');
            MESSAGES_LIST.appendChild(currentAssistantMessage);
        }

        const textElement = currentAssistantMessage.querySelector('.message-text');
        if (textElement) {
            textElement.textContent += token;
        }

        scrollToBottom();
    }

    /**
     * Create a message DOM element.
     */
    function createMessageElement(role, content) {
        const message = document.createElement('div');
        message.className = `message message-${role}`;
        message.dataset.role = role;

        const avatarLabel = role === 'user' ? 'U' : 'AI';
        const avatarClass = role === 'user' ? 'user-avatar' : 'assistant-avatar';

        message.innerHTML = `
            <div class="message-avatar">
                <span class="avatar-icon ${avatarClass}">${avatarLabel}</span>
            </div>
            <div class="message-content">
                <div class="message-text">${escapeHtml(content)}</div>
            </div>
        `;

        return message;
    }

    /**
     * Show typing indicator.
     */
    function showTypingIndicator() {
        const existing = document.querySelector('[data-typing="true"]');
        if (existing) return;

        if (TYPING_TEMPLATE) {
            const indicator = TYPING_TEMPLATE.content.cloneNode(true);
            MESSAGES_LIST.appendChild(indicator);
            scrollToBottom();
        }
    }

    /**
     * Hide typing indicator.
     */
    function hideTypingIndicator() {
        const indicator = document.querySelector('[data-typing="true"]');
        if (indicator) {
            indicator.remove();
        }
    }

    /**
     * Show error message.
     */
    function showError(message) {
        const errorDiv = document.createElement('div');
        errorDiv.className = 'message message-error';
        errorDiv.innerHTML = `
            <div class="message-content">
                <div class="message-text">Error: ${escapeHtml(message)}</div>
            </div>
        `;
        MESSAGES_LIST.appendChild(errorDiv);
    }

    /**
     * Show connection status.
     */
    function showConnectionStatus(text, state) {
        if (!CONNECTION_STATUS) return;

        const dot = CONNECTION_STATUS.querySelector('.status-dot');
        const textSpan = CONNECTION_STATUS.querySelector('.status-text');

        if (dot) {
            dot.className = `status-dot status-${state}`;
        }
        if (textSpan) {
            textSpan.textContent = text;
        }

        CONNECTION_STATUS.classList.remove('hidden');
    }

    /**
     * Scroll messages to bottom.
     */
    function scrollToBottom() {
        MESSAGES_CONTAINER.scrollTop = MESSAGES_CONTAINER.scrollHeight;
    }

    /**
     * Enable input after streaming completes.
     */
    function enableInput() {
        if (MESSAGE_INPUT) MESSAGE_INPUT.disabled = false;
        if (SEND_BUTTON) SEND_BUTTON.disabled = false;
        if (MESSAGE_INPUT) MESSAGE_INPUT.focus();
    }

    /**
     * Disable input during streaming.
     */
    function disableInput() {
        if (MESSAGE_INPUT) MESSAGE_INPUT.disabled = true;
        if (SEND_BUTTON) SEND_BUTTON.disabled = true;
    }

    /**
     * Escape HTML to prevent XSS.
     */
    function escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    /**
     * Handle form submission.
     */
    function handleSubmit(event) {
        event.preventDefault();

        const message = MESSAGE_INPUT.value.trim();
        if (!message || isStreaming) return;

        // Add user message to UI
        const userMessage = createMessageElement('user', message);
        MESSAGES_LIST.appendChild(userMessage);

        // Clear input
        MESSAGE_INPUT.value = '';

        // Send via WebSocket
        if (ws && ws.readyState === WebSocket.OPEN) {
            ws.send(JSON.stringify({ message: message }));
            isStreaming = true;
            disableInput();
        } else {
            showError('Not connected to server');
        }

        scrollToBottom();
    }

    // Initialize on DOM ready
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initWebSocket);
    } else {
        initWebSocket();
    }

    // Attach form handler
    if (CHAT_FORM) {
        CHAT_FORM.addEventListener('submit', handleSubmit);
    }
})();

/* Tailwind-inspired custom styles for chat interface */

/* CSS Variables */
:root {
    --color-primary: #3b82f6;
    --color-primary-hover: #2563eb;
    --color-user-bg: #3b82f6;
    --color-user-text: #ffffff;
    --color-assistant-bg: #f3f4f6;
    --color-assistant-text: #1f2937;
    --color-border: #e5e7eb;
    --color-text: #374151;
    --color-text-muted: #6b7280;
    --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
    --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1);
    --radius-lg: 0.5rem;
    --radius-xl: 0.75rem;
}

/* Reset and base */
*, *::before, *::after {
    box-sizing: border-box;
}

body {
    margin: 0;
    font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 0.95rem;
    line-height: 1.5;
    color: var(--color-text);
    background-color: #f9fafb;
    height: 100vh;
    overflow: hidden;
}

/* Chat container */
.chat-container {
    display: flex;
    flex-direction: column;
    height: 100vh;
    max-width: 56rem;
    margin: 0 auto;
    background-color: #ffffff;
    box-shadow: var(--shadow-md);
}

/* Header */
.chat-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1rem 1.5rem;
    border-bottom: 1px solid var(--color-border);
    background-color: #ffffff;
}

.chat-title {
    font-size: 1.25rem;
    font-weight: 600;
    color: #111827;
    margin: 0;
}

.header-status {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.model-indicator {
    font-size: 0.75rem;
    color: var(--color-text-muted);
    padding: 0.25rem 0.75rem;
    background-color: #f3f4f6;
    border-radius: 9999px;
}

/* Messages container */
.messages-container {
    flex: 1;
    overflow-y: auto;
    padding: 1.5rem;
    scroll-behavior: smooth;
}

.messages-list {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    min-height: 100%;
}

/* Welcome message */
.welcome-message {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    padding: 3rem 1rem;
    color: var(--color-text-muted);
}

.welcome-icon {
    margin-bottom: 1rem;
    color: var(--color-primary);
}

.welcome-message h2 {
    font-size: 1.5rem;
    font-weight: 600;
    color: #111827;
    margin: 0 0 0.5rem 0;
}

.welcome-message p {
    margin: 0;
    max-width: 24rem;
}

/* Message bubbles */
.message {
    display: flex;
    gap: 0.75rem;
    max-width: 100%;
    animation: fadeIn 0.2s ease-out;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(8px); }
    to { opacity: 1; transform: translateY(0); }
}

.message-user {
    flex-direction: row-reverse;
}

.message-avatar {
    flex-shrink: 0;
}

.avatar-icon {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    font-size: 0.75rem;
    font-weight: 600;
}

.user-avatar {
    background-color: var(--color-primary);
    color: var(--color-user-text);
}

.assistant-avatar {
    background-color: #10b981;
    color: #ffffff;
}

.message-content {
    flex: 1;
    min-width: 0;
}

.message-text {
    padding: 0.75rem 1rem;
    border-radius: var(--radius-xl);
    word-wrap: break-word;
    white-space: pre-wrap;
}

.message-user .message-text {
    background-color: var(--color-user-bg);
    color: var(--color-user-text);
    border-bottom-right-radius: 0.25rem;
}

.message-assistant .message-text {
    background-color: var(--color-assistant-bg);
    color: var(--color-assistant-text);
    border-bottom-left-radius: 0.25rem;
}

/* Typing indicator */
.typing-indicator {
    display: flex;
    gap: 0.25rem;
    padding: 0.75rem 1rem;
    background-color: var(--color-assistant-bg);
    border-radius: var(--radius-xl);
    border-bottom-left-radius: 0.25rem;
    width: fit-content;
}

.typing-dot {
    width: 0.5rem;
    height: 0.5rem;
    background-color: var(--color-text-muted);
    border-radius: 50%;
    animation: bounce 1.4s infinite ease-in-out;
}

.typing-dot:nth-child(1) { animation-delay: -0.32s; }
.typing-dot:nth-child(2) { animation-delay: -0.16s; }

@keyframes bounce {
    0%, 80%, 100% { transform: scale(0.8); opacity: 0.5; }
    40% { transform: scale(1); opacity: 1; }
}

/* Chat input */
.chat-input-container {
    border-top: 1px solid var(--color-border);
    padding: 1rem 1.5rem;
    background-color: #ffffff;
}

.chat-input-form {
    margin: 0;
}

.input-wrapper {
    display: flex;
    gap: 0.75rem;
    align-items: center;
}

.chat-input {
    flex: 1;
    padding: 0.75rem 1rem;
    font-size: 0.95rem;
    border: 1px solid var(--color-border);
    border-radius: var(--radius-lg);
    outline: none;
    transition: border-color 0.15s ease, box-shadow 0.15s ease;
}

.chat-input:focus {
    border-color: var(--color-primary);
    box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.1);
}

.send-button {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 2.75rem;
    height: 2.75rem;
    padding: 0;
    border: none;
    border-radius: var(--radius-lg);
    background-color: var(--color-primary);
    color: #ffffff;
    cursor: pointer;
    transition: background-color 0.15s ease;
}

.send-button:hover {
    background-color: var(--color-primary-hover);
}

.send-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Connection status */
.connection-status {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-top: 0.5rem;
    font-size: 0.75rem;
    color: var(--color-text-muted);
}

.connection-status.hidden {
    display: none;
}

.status-dot {
    width: 0.5rem;
    height: 0.5rem;
    background-color: #fbbf24;
    border-radius: 50%;
    animation: pulse 2s infinite;
}

@keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.5; }
}

/* Error message */
.message-error .message-text {
    background-color: #fef2f2;
    color: #dc2626;
    border: 1px solid #fecaca;
}

/* Scrollbar styling */
.messages-container::-webkit-scrollbar {
    width: 0.5rem;
}

.messages-container::-webkit-scrollbar-track {
    background: #f1f5f9;
}

.messages-container::-webkit-scrollbar-thumb {
    background: #cbd5e1;
    border-radius: 0.25rem;
}

.messages-container::-webkit-scrollbar-thumb:hover {
    background: #94a3b8;
}

/* Responsive */
@media (max-width: 640px) {
    .chat-header {
        padding: 0.75rem 1rem;
    }

    .messages-container {
        padding: 1rem;
    }

    .chat-input-container {
        padding: 0.75rem 1rem;
    }

    .welcome-message {
        padding: 2rem 0.5rem;
    }
}

